def format_args(self, args):
    formatted_args = []
    for arg in args:
        if isinstance(arg, dbus.Boolean):
            formatted_args.append(str(bool(arg)))
        elif isinstance(arg, dbus.Byte):
            formatted_args.append(str(int(arg)))
        elif isinstance(arg, int) or isinstance(arg, long):
            formatted_args.append(str(arg))
        elif isinstance(arg, str) or isinstance(arg, unicode):
            formatted_args.append('"' + str(arg) + '"')
        elif isinstance(arg, list):
            formatted_args.append('[' + ', '.join([format_arg(x) for x in arg]) + ']')
        elif isinstance(arg, dict):
            formatted_args.append('{')
            first = True
            for k, v in arg.items():
                if first:
                    first = False
                else:
                    formatted_args.append(', ')
                formatted_args.append(str(k) + ': ' + format_arg(v))
            formatted_args.append('}')
    return ' '.join(formatted_args)

def AddObject(self, path, interface, properties, methods):
    # Validate input arguments
    if not isinstance(path, str):
        raise dbus.exceptions.DBusException('Invalid path')
    if not isinstance(interface, str):
        raise dbus.exceptions.DBusException('Invalid interface')
    if not isinstance(properties, dict):
        raise dbus.exceptions.DBusException('Invalid properties')

