class Vault(object):
    def __init__(self, password):
        self.password = password
        self.vault = VaultLib(password)

    def load(self, stream):
        try:
            data = yaml.safe_load(stream)
            if not isinstance(data, dict):
                raise ValueError("Invalid YAML syntax")
            # Additional validation for malicious characters
            for key, value in data.items():
                if not isinstance(key, str) or not isinstance(value, str):
                    raise ValueError("Invalid data type")
            return self.vault.decrypt(data)
        except yaml.constructor.ConstructorError as e:
            raise ValueError("Invalid YAML syntax: " + str(e))

    def dump(self, data, stream=None):
        try:
            yaml_text = yaml.dump(data, default_flow_style=False, allow_unicode=True)
            encrypted = self.vault.encrypt(yaml_text)
            if stream:
                stream.write(encrypted)
            else:
                return encrypted
        except Exception as e:
            raise ValueError("Encryption error: " + str(e))
```

